import { describe, it, expect } from "vitest";
import { quote, claim } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("quote - empty and single-item base premiums", () => {
    it("empty item list yields premium of 5G (processing fee only)", () => {
      expect(quote({ items: [], years: 0, priorContract: false })).toEqual({ premium: 5 });
    });
    it("single sword (no modifiers, 0 years, no prior contract) yields 100G base + 10G first insurance + 5G fee = 115G", () => {
      expect(quote({ items: [{ type: "sword" }], years: 0, priorContract: false })).toEqual({ premium: 115 });
    });
    it("single amulet yields 60G base + 10G first insurance + 5G fee = 75G", () => {
      expect(quote({ items: [{ type: "amulet" }], years: 0, priorContract: false })).toEqual({ premium: 75 });
    });
    it("single staff yields 80G base + 10G first insurance + 5G fee = 95G", () => {
      expect(quote({ items: [{ type: "staff" }], years: 0, priorContract: false })).toEqual({ premium: 95 });
    });
    it("single potion yields 40G base + 10G first insurance + 5G fee = 55G", () => {
      expect(quote({ items: [{ type: "potion" }], years: 0, priorContract: false })).toEqual({ premium: 55 });
    });
  });

  describe("quote - components and building blocks", () => {
    it("single rune yields 25G base premium", () => {
      expect(quote({ items: [{ type: "rune" }], years: 0, priorContract: false })).toEqual({ premium: 40 });
    });
    it("2 runes yields 50G base premium (no block)", () => {
      expect(quote({ items: [{ type: "rune" }, { type: "rune" }], years: 0, priorContract: false })).toEqual({ premium: 75 });
    });
    it("3 runes yields 60G base premium (block applies)", () => {
      expect(quote({ items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }], years: 0, priorContract: false })).toEqual({ premium: 95 });
    });
    it("4 runes yields 100G base premium (no block — block requires exactly 3)", () => {
      expect(quote({ items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }], years: 0, priorContract: false })).toEqual({ premium: 145 });
    });
    it("7 runes yields 175G base premium", () => {
      expect(quote({ items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }], years: 0, priorContract: false })).toEqual({ premium: 250 });
    });
    it("2 runes + 1 moonstone yields 75G base premium (no block: different types)", () => {
      expect(quote({ items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }], years: 0, priorContract: false })).toEqual({ premium: 110 });
    });
    it("3 runes + 3 moonstones yields 120G base premium (two separate blocks)", () => {
      expect(quote({ items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "moonstone" }, { type: "moonstone" }, { type: "moonstone" }], years: 0, priorContract: false })).toEqual({ premium: 185 });
    });
  });

  describe("quote - per-item modifiers", () => {
    it("cursed sword adds 50G curse surcharge (50% of sword's 100G base)", () => {
      expect(quote({ items: [{ type: "sword", cursed: true }], years: 0, priorContract: false })).toEqual({ premium: 165 });
    });
    it("sword with enchantment exactly 5 adds 30G high-enchantment surcharge", () => {
      expect(quote({ items: [{ type: "sword", enchantment: 5 }], years: 0, priorContract: false })).toEqual({ premium: 145 });
    });
    it("sword with enchantment 4 has no high-enchantment surcharge", () => {
      expect(quote({ items: [{ type: "sword", enchantment: 4 }], years: 0, priorContract: false })).toEqual({ premium: 115 });
    });
    it("cursed sword with enchantment 5 applies both curse and high-enchantment surcharges", () => {
      expect(quote({ items: [{ type: "sword", cursed: true, enchantment: 5 }], years: 0, priorContract: false })).toEqual({ premium: 195 });
    });
    it("first insurance surcharge applies per item (each item in a quote is a first insurance)", () => {
      // 2 moonstones: 25G + 25G base = 50G. First insurance is 10% per item: 2.5G + 2.5G = 5G. + 5G fee = 60G.
      expect(quote({ items: [{ type: "moonstone" }, { type: "moonstone" }], years: 0, priorContract: false })).toEqual({ premium: 60 });
    });
  });

  describe("quote - policy-wide modifiers", () => {
    it.todo("customer with exactly 2 years receives 20% loyalty discount on policy base premium");
    it.todo("follow-up contract (second quote in scenario) applies 15% discount on policy base premium");
    it.todo("processing fee of 5G is added at the very end after all modifiers");
  });

  describe("quote - modifier scope on multi-item policies", () => {
    it.todo("cursed sword + plain amulet: curse adds 50G (50% of cursed sword's base), not of policy total → 210G before fee/loyalty/etc");
  });

  describe("quote - rounding", () => {
    it.todo("premium of 197.5G rounds UP to 198G (in MHPCO's favor)");
  });

  describe("quote - integration examples from spec", () => {
    it.todo("newcomer (0 years, no prior contract) with cursed sword (steel, enchantment 3) → 165G");
    it.todo("3-year customer's second quote with cursed sword (steel, enchantment 7) → 160G");
  });

  describe("claim - basic payouts and deductible", () => {
    it.todo("regular sword (steel, enchantment 3), damage 500G → payout 400G (full minus 100G deductible)");
    it.todo("damage to a rune (insurance value 250G), damage 200G → payout 100G (full minus 100G deductible)");
    it.todo("deductible applies once per damaged item (dragon attack: sword 500G + amulet 300G → payout 600G)");
  });

  describe("claim - special clauses", () => {
    it.todo("sword with enchantment ≥ 8 reimburses 50% of damage (then deductible)");
    it.todo("dragon-material sword fully reimbursed (then deductible)");
    it.todo("dragon-material sword, enchantment 9, damage 1000G → payout 400G (50% rule wins, then deductible)");
    it.todo("dragon-material sword, enchantment 5, damage 800G → payout 700G (only dragon clause)");
    it.todo("steel sword, enchantment 9, damage 1000G → payout 400G (only high-enchantment clause)");
    it.todo("dragon-material sword, enchantment exactly 8, damage 1000G → payout 400G (high-enchantment clause applies, then deductible)");
  });

  describe("claim - payout cap (2x insurance sum, cumulative)", () => {
    it.todo("policy covering sword has cap 2000G (2 × 1000G insurance value)");
    it.todo("cursed sword cap is 2000G — premium modifiers do not raise cap (based on unmodified insurance value)");
    it.todo("policy covers sword + 3 runes: insurance sum 1750G (block discount affects premium only, not insurance sum)");
    it.todo("two successive 1500G claims on a sword (cap 2000G): first payout 1400G (cap remaining 600G); second payout 600G (cap remaining 0G)");
  });

  describe("claim - rounding", () => {
    it.todo("payout of 350.5G rounds DOWN to 350G (in MHPCO's favor)");
  });

  describe("claim - multiple items of the same type", () => {
    it.todo("policy covers two swords: insurance sum 2000G, cap 4000G");
    it.todo("damages array with two sword entries on a 2-sword policy: each entry treated as separate damage with own deductible");
  });

  describe("CLI - scenario processing", () => {
    it.todo("CLI reads JSON scenario from stdin and writes results array to stdout in same order as steps");
    it.todo("claim step references earlier quote via zero-based step index in policy field");
    it.todo("quote result contains integer premium field");
    it.todo("claim result contains integer payout and remainingCap fields");
  });

  describe("CLI - error cases", () => {
    it.todo("quote with unknown item type (e.g. broomstick) → non-zero exit, error to stderr, no results to stdout");
    it.todo("claim referencing damage on item not in policy → non-zero exit, error to stderr");
    it.todo("claim referencing damage on item with unknown type → non-zero exit, error to stderr");
    it.todo("claim with negative damage amount → non-zero exit, error to stderr");
    it.todo("claim with more damage entries of a type than policy covers (e.g. two sword damages, one sword insured) → non-zero exit, whole claim rejected");
  });
});

