const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE = 10;
const BLOCK_OF_THREE_PREMIUM = 60;
const BLOCK_SIZE = 3;
const CURSE_SURCHARGE_RATE = 0.5;
const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
const HIGH_ENCHANTMENT_THRESHOLD = 5;
const LOYALTY_DISCOUNT_RATE = 0.2;
const LOYALTY_YEARS_THRESHOLD = 2;
const FOLLOW_UP_DISCOUNT_RATE = 0.15;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

type Item = { type: string; cursed?: boolean; enchantment?: number };

function isHighlyEnchanted(item: Item): boolean {
  return item.enchantment !== undefined && item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD;
}

function surchargeRate(item: Item): number {
  return (item.cursed ? CURSE_SURCHARGE_RATE : 0)
    + (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_SURCHARGE_RATE : 0);
}

function itemBasePremium(item: Item): number {
  const base = BASE_PREMIUMS[item.type];
  return base + base * surchargeRate(item);
}

function sumIndividualBasePremiums(items: Item[]): number {
  return items.reduce((sum, item) => sum + itemBasePremium(item), 0);
}

function groupByType(items: Item[]): Record<string, Item[]> {
  const groups: Record<string, Item[]> = {};
  for (const item of items) {
    if (!groups[item.type]) groups[item.type] = [];
    groups[item.type].push(item);
  }
  return groups;
}

function premiumForGroup(groupItems: Item[]): number {
  return groupItems.length === BLOCK_SIZE
    ? BLOCK_OF_THREE_PREMIUM
    : sumIndividualBasePremiums(groupItems);
}

function calculateBasePremium(items: Item[]): number {
  const groups = groupByType(items);
  return Object.values(groups).reduce((total, group) => total + premiumForGroup(group), 0);
}

function loyaltyDiscount(basePremium: number, years: number): number {
  return years >= LOYALTY_YEARS_THRESHOLD ? basePremium * LOYALTY_DISCOUNT_RATE : 0;
}

function followUpDiscount(basePremium: number, priorContract: boolean): number {
  return priorContract ? basePremium * FOLLOW_UP_DISCOUNT_RATE : 0;
}

export function quote({ items, years, priorContract }: { items: Item[]; years: number; priorContract: boolean }): { premium: number } {
  const basePremium = calculateBasePremium(items);
  const totalDiscounts = loyaltyDiscount(basePremium, years) + followUpDiscount(basePremium, priorContract);
  const firstInsuranceSurcharges = items.length * FIRST_INSURANCE_SURCHARGE;
  return { premium: Math.ceil(basePremium - totalDiscounts + firstInsuranceSurcharges + PROCESSING_FEE) };
}

export function claim(_input: unknown): unknown {
  return undefined;
}

